import { ApolloServer, gql } from 'apollo-server';
const server = new ApolloServer({
    typeDefs: gql`
        type Invoice {
            id: ID!
            name: String!
            amount: Float!
            currency: String!
            dueDate: Date!
            status: Status!
        }

        enum Status {
            PENDING
            PAID
            FAILED
        }

        type Query {
            invoice(id: ID): Invoice
        }
    `,
});

server.listen().then(({ url }) => console.log(`Server ready at ${url}`));